import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    /**
     * Asserts the structural partition property:
     * all balances[0..splitIndex-1] < threshold,
     * all balances[splitIndex..n-1] >= threshold.
     */
    private void assertSplitProperty(int[] balances, int splitIndex, int threshold) {
        for (int i = 0; i < splitIndex; i++) {
            assertTrue(balances[i] < threshold,
                "Expected balances[" + i + "]="+ balances[i] + " < " + threshold);
        }
        for (int i = splitIndex; i < balances.length; i++) {
            assertTrue(balances[i] >= threshold,
                "Expected balances[" + i + "]="+ balances[i] + " >= " + threshold);
        }
    }

    @Test
    void classic() {
        int[] balances = {1200, 50, 3000, 200, 800};
        int split = new Solution().splitByThreshold(balances, 1000);
        assertEquals(3, split);
        assertSplitProperty(balances, split, 1000);
    }

    @Test
    void allBelowThreshold() {
        int[] balances = {500, 100, 300};
        int split = new Solution().splitByThreshold(balances, 1000);
        assertEquals(3, split);
        assertSplitProperty(balances, split, 1000);
    }

    @Test
    void allAboveThreshold() {
        int[] balances = {2000, 1500, 3000};
        int split = new Solution().splitByThreshold(balances, 1000);
        assertEquals(0, split);
        assertSplitProperty(balances, split, 1000);
    }

    @Test
    void exactlyAtThreshold() {
        // elements equal to threshold go to the >= side
        int[] balances = {1000, 500, 1000, 200};
        int split = new Solution().splitByThreshold(balances, 1000);
        assertEquals(2, split); // {500,200} below, {1000,1000} at-or-above
        assertSplitProperty(balances, split, 1000);
    }

    @Test
    void singleElement_below() {
        int[] balances = {300};
        int split = new Solution().splitByThreshold(balances, 1000);
        assertEquals(1, split);
        assertSplitProperty(balances, split, 1000);
    }

    @Test
    void singleElement_above() {
        int[] balances = {5000};
        int split = new Solution().splitByThreshold(balances, 1000);
        assertEquals(0, split);
        assertSplitProperty(balances, split, 1000);
    }

    @Test
    void alreadyPartitioned() {
        // already in correct order — must not corrupt
        int[] balances = {100, 200, 300, 1500, 2000};
        int split = new Solution().splitByThreshold(balances, 1000);
        assertEquals(3, split);
        assertSplitProperty(balances, split, 1000);
    }
}
